phase1.code:
#include <iostream>

int globalVar = 42;  // Global (static storage)

void stackExample() {
    int localVar = 10;      // Stack
    int anotherLocal = 20;  // Stack
    std::cout << "Stack variables:" << std::endl;
    std::cout << "localVar: " << localVar << " (address: " << &localVar << ")" << std::endl;
    std::cout << "anotherLocal: " << anotherLocal << " (address: " << &anotherLocal << ")" << std::endl;
}

void heapExample() {
    int* heapVar = new int(100);  // Heap!
    std::cout << "\nHeap variable:" << std::endl;
    std::cout << "*heapVar: " << *heapVar << " (address: " << heapVar << ")" << std::endl;
    delete heapVar;  // Must free heap memory!
}

int main() {
    std::cout << "=== Stack vs Heap ===" << std::endl;
    std::cout << "Global variable: " << globalVar << " (address: " << &globalVar << ")" << std::endl;

    stackExample();
    heapExample();

    std::cout << "\n--- Key Differences ---" << std::endl;
    std::cout << "Stack: automatic, fast, limited size" << std::endl;
    std::cout << "Heap: manual, slower, larger size" << std::endl;

    return 0;
}

