#include <iostream>

int globalVar = 10;

int main() {
    int stackVar = 5;
    int* heapVar = new int(15);

    std::cout << "Stack variable: " << stackVar 
              << " (address: " << &stackVar << ")" << std::endl;
    std::cout << "Global variable: " << globalVar 
              << " (address: " << &globalVar << ")" << std::endl;
    std::cout << "Heap variable: " << *heapVar 
              << " (address: " << heapVar << ")" << std::endl;

    delete heapVar;

    return 0;
}
